def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    total_bins = len(bins)
    for i in range(total_bins):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 2:
            score += 2000 + 20 * (ratio - 2)**3
        elif ratio > 1:
            score += 1500 + 15 * (ratio - 1)**2
        else:
            if ratio > 0.85:
                score += 80 * ratio
            elif ratio > 0.7:
                score += 60 * ratio
            elif ratio > 0.4:
                score += 40 * ratio
            else:
                score += 20 * ratio
            if capacity < 5:
                score += 10
            elif capacity < 20:
                score += 5
            elif capacity > 200:
                score -= 10
            elif capacity > 150:
                score -= 5
        for j in range(total_bins):
            if j != i:
                diff = abs(capacity - bins[j])
                if diff < 10:
                    score += 0.05 * diff
                else:
                    score -= 0.02 * diff
        if i % 3 == 0:
            score *= 1.15
        elif i % 3 == 1:
            score *= 0.85
        else:
            score *= 1.05
        if item % 2 == 0:
            score *= 1.02
        else:
            score *= 0.98
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if len(finite_priorities) == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    min_finite = np.min(finite_priorities)
    mean_finite = np.mean(finite_priorities)
    for i in range(total_bins):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite + abs(max_finite - min_finite) + mean_finite * 0.5
    return priorities
